SELECT COUNT(*)
FROM reservations
WHERE house_id = #{houseId}
  AND status != 'CANCELLED'
  AND checkin_date < #{checkoutDate}
  AND checkout_date > #{checkinDate}

SELECT reservation_id AS reservationId, guest_id AS guestId, house_id AS houseId, status, checkin_date AS checkinDate, checkout_date AS checkoutDate, total_price AS totalPrice, created_at AS createdAt, updated_at AS updatedAt FROM reservations WHERE guest_id = #{guestId}
AND status = #{status}
AND #{date} BETWEEN checkin_date AND checkout_date
ORDER BY created_at DESC

mapper.update:
UPDATE reservations
SET status = #{status}, updated_at = NOW()
WHERE reservation_id = #{reservationId}
